// Achievement data interface
export interface AchievementData {
  total_payout?: number;
  highest_payout?: number;
  best_trade?: number;
  longest_funded_days?: number;
}

// Props interface for the component
export interface AchievementsProps {
  data?: AchievementData;
  className?: string;
}

// Achievement card component
interface AchievementCardProps {
  icon: React.ReactNode;
  label: string;
  value: string;
  className?: string;
}

const AchievementCard: React.FC<AchievementCardProps> = ({
  icon,
  label,
  value,
  className = "",
}) => {
  return (
    <div
      className={`flex items-center gap-4 p-4 md:p-5 rounded-2xl border border-[#3AB3FF] bg-[#3AB3FF]/10 shadow-[0_0_30px_rgba(58,179,255,0.1)] hover:shadow-[0_0_40px_rgba(58,179,255,0.15)] transition-all duration-300 ${className}`}
    >
      {/* Icon container */}
              <div className="flex items-center justify-center w-10 h-10 md:w-12 md:h-12 p-3 rounded-lg border border-[#3AB3FF] bg-[#3AB3FF]/5 shadow-[0px_-8px_32px_0px_rgba(58,179,255,0.06)_inset]">
        {icon}
      </div>

      {/* Content */}
      <div className="flex flex-col justify-center gap-1 md:gap-2 flex-1">
        <div className="text-[#85A8C3] text-xs md:text-sm font-normal leading-normal tracking-[-0.42px] line-clamp-1 overflow-hidden text-ellipsis">
          {label}
        </div>
        <div className="text-[#E4EEF5] text-lg md:text-2xl font-medium leading-normal tracking-[-0.72px]">
          {value}
        </div>
      </div>
    </div>
  );
};

// Format currency values
const formatCurrency = (amount: number | undefined): string => {
  if (amount === undefined || amount === null) return "$0.00";
  return `$${amount.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
};

// Format days
const formatDays = (days: number | undefined): string => {
  if (days === undefined || days === null) return "0 days";
  return `${days} day${days !== 1 ? "s" : ""}`;
};

// Main Achievements component
const Achievements: React.FC<AchievementsProps> = ({
  data = {},
  className = "",
}) => {
  const { t } = useTranslation();
  const {
    total_payout = 0,
    highest_payout = 0,
    best_trade = 0,
    longest_funded_days = 0,
  } = data;

  return (
    <div
      className={`rounded-2xl border border-[rgba(58,179,255,0.05)] bg-[#3AB3FF]/10 shadow-[0_0_30px_rgba(58,179,255,0.08)] p-4 md:p-6 ${className}`}
    >
      {/* Header */}
      <div className="flex items-center gap-3 w-full mb-6 md:mb-8">
        {/* Trophy icon container */}
        <div className="flex items-center justify-center w-10 h-10 md:w-11 md:h-11 p-[10.667px] rounded-lg border border-[#3AB3FF] bg-[#3AB3FF]/5 shadow-[0px_0px_16px_0px_rgba(58,179,255,0.12),_0px_-8px_32px_0px_rgba(58,179,255,0.06)_inset]">
          <CupIcon />
        </div>

        {/* Title */}
        <h2 className="text-[#E4EEF5] text-lg md:text-xl font-medium leading-normal tracking-[-0.72px]">
          {t('achievements.title')}
        </h2>
      </div>

      {/* Achievement Cards Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4 w-full">
        <AchievementCard
          icon={<HandCoinsIcon />}
          label={t('achievements.totalPayout')}
          value={formatCurrency(total_payout)}
        />

        <AchievementCard
          icon={<TrophyIcon />}
          label={t('achievements.highestPayout')}
          value={formatCurrency(highest_payout)}
        />

        <AchievementCard
          icon={<RocketIcon />}
          label={t('achievements.bestTrade')}
          value={formatCurrency(best_trade)}
        />

        <AchievementCard
          icon={<WatchIcon />}
          label={t('achievements.longestTimeFunded')}
          value={formatDays(longest_funded_days)}
        />
      </div>
    </div>
  );
};

export default Achievements;
